import java.util.HashMap;
import java.util.Map;

public class Main {
    public static void main(String[] args) {
        String text = "Merhaba dunya bu bir test metni. Bu metin kelime sayma icin kullanilacak. Merhaba tekrar!";

        // Noktalama isaretlerini temizle
        String cleanText = text.replace(".", "").replace(",", "").replace("!", "");
        String[] words = cleanText.toLowerCase().split("\\s+");

        System.out.println("Toplam kelime sayisi: " + words.length);
        System.out.println("Toplam karakter sayisi: " + text.length());

        // Kelime frekansi
        HashMap<String, Integer> wordCount = new HashMap<>();
        for (String word : words) {
            wordCount.put(word, wordCount.getOrDefault(word, 0) + 1);
        }

        System.out.println("\nKelime frekanslari:");
        for (Map.Entry<String, Integer> entry : wordCount.entrySet()) {
            System.out.println("'" + entry.getKey() + "': " + entry.getValue() + " kez");
        }

        // En uzun kelime
        String longestWord = words[0];
        for (String word : words) {
            if (word.length() > longestWord.length()) {
                longestWord = word;
            }
        }
        System.out.println("\nEn uzun kelime: '" + longestWord + "' (" + longestWord.length() + " karakter)");

        // Ortalama kelime uzunlugu
        int totalLength = 0;
        for (String word : words) totalLength += word.length();
        double avgLength = (double) totalLength / words.length;
        System.out.printf("Ortalama kelime uzunlugu: %.2f%n", avgLength);
    }
}
